 void OnGUI(){LoadIllustratedUi();EnsureBook();InitStyles();EnsureSocialStyles();EnsureHomeTextures();ApplyIllustratedStyles();TuneIllustratedText();ApplyScreenTheme();DrawScreenBackground();if(screen==ScreenId.Hub){HubScreenBook();return;}if(screen==ScreenId.Map){MapScrollScreen();return;}if(screen==ScreenId.Battle){BattleTableScreen();return;}Rect content=ContentRect();GUILayout.BeginArea(content);TopBar();scroll.x=0;scroll=GUILayout.BeginScrollView(scroll,false,false,GUIStyle.none,GUI.skin.verticalScrollbar);switch(screen){case ScreenId.Character:CharacterScreen();break;case ScreenId.Status:StatusScreenBook();break;case ScreenId.Vault:VaultScreen();break;case ScreenId.Faction:FactionScreenBook();break;case ScreenId.Expedition:ExpeditionScreenBook();break;case ScreenId.Pack:PackingScreen();break;case ScreenId.Reward:RewardScreen();break;case ScreenId.Shop:ShopScreen();break;case ScreenId.Event:EventScreen();break;case ScreenId.Compendium:CompendiumScreenBook();break;case ScreenId.GameOver:GameOverScreen();break;}GUILayout.EndScrollView();GUILayout.EndArea();if(screen==ScreenId.Expedition)DrawExpeditionActionDock();if(ShowBaseNavigation())DrawBookBookmarks();}
 void ApplyBookTypography(){if(!BookUiActive())return;header.fontSize=23;header.fontStyle=FontStyle.Bold;body.fontSize=17;body.fontStyle=FontStyle.Bold;button.fontSize=18;button.fontStyle=FontStyle.Bold;card.fontSize=16;screenSubtitle.fontSize=16;screenSubtitle.fontStyle=FontStyle.Bold;}
 Rect BookFrameRect(){Rect viewport=new(6,4,Screen.width-12,Screen.height-8);if(bookSpread==null)return viewport;return FitAspect(viewport,bookSpread.width/(float)bookSpread.height);}
 Rect BookLeftPageRect(){Rect book=BookFrameRect();return new Rect(book.x+book.width*.113f,book.y+book.height*.069f,book.width*.371f,book.height*.842f);}
 Rect BookRightPageRect(){Rect book=BookFrameRect();return new Rect(book.x+book.width*.516f,book.y+book.height*.069f,book.width*.371f,book.height*.842f);}
 Rect ContentRect(){if(screen==ScreenId.Hub)return new Rect(0,0,Screen.width,Screen.height);if(bookSpread!=null){Rect left=BookLeftPageRect(),right=BookRightPageRect();float height=Mathf.Min(left.height,right.height);if(screen==ScreenId.Expedition)height-=82f;return new Rect(left.x,left.y,right.xMax-left.x,height);}float x=Mathf.Max(58,Screen.width*.065f),y=Mathf.Max(34,Screen.height*.045f);return new Rect(x,y,Screen.width-x*2,Screen.height-y*2);}
 float BookHeaderColumnWidth()=>BookLeftPageRect().width;
 float BookHeaderGutter()=>BookRightPageRect().x-BookLeftPageRect().xMax;
 float BookPageColumnWidth()=>Mathf.Max(190f,BookLeftPageRect().width-30f);
 float BookPageGutter()=>BookHeaderGutter()+30f;
