 void BattleScreenPolished(){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);BeginPage("戦闘",dungeon.name);GUILayout.BeginHorizontal();Rect playerPanel=GUILayoutUtility.GetRect(360,280,GUILayout.ExpandWidth(true));DrawCombatPortrait(playerPanel,true);GUILayout.Space(16);GUILayout.Label("対",new GUIStyle(title){alignment=TextAnchor.MiddleCenter,fontSize=34},GUILayout.Width(52),GUILayout.Height(280));GUILayout.Space(16);Rect enemyPanel=GUILayoutUtility.GetRect(360,280,GUILayout.ExpandWidth(true));DrawCombatPortrait(enemyPanel,false);GUILayout.EndHorizontal();GUILayout.Space(10);GUILayout.Label(battle.log,hubLabel,GUILayout.Height(42));if(run.consumables.Count>0){GUILayout.BeginHorizontal(GUI.skin.box,GUILayout.Height(58));GUILayout.Label("消耗品",header,GUILayout.Width(90));for(int i=0;i<run.consumables.Count;i++){int index=i;if(GUILayout.Button(ConsumableSystem.Name(run.consumables[i]),navButton,GUILayout.Width(115),GUILayout.Height(40))){ConsumableSystem.Use(run,battle,index);if(battle.enemyHp<=0){EndPage();WinBattle();return;}break;}}GUILayout.FlexibleSpace();GUILayout.EndHorizontal();}GUILayout.Space(12);GUILayout.BeginHorizontal();GUILayout.Label("手札",header);GUILayout.FlexibleSpace();GUILayout.Label($"山札 {run.draw.Count}   捨て札 {run.discard.Count}",badge,GUILayout.Width(165),GUILayout.Height(28));GUILayout.EndHorizontal();GUILayout.BeginHorizontal();for(int i=0;i<run.hand.Count;i++){int index=i;var combatCard=run.hand[i];bool affordable=combatCard.cost<=run.energy;GUI.enabled=affordable;Rect cardRect=GUILayoutUtility.GetRect(170,210,GUILayout.Width(170),GUILayout.Height(210));DrawCombatCard(cardRect,combatCard,affordable);if(GUI.Button(cardRect,GUIContent.none,hotspot)&&BattleSystem.Play(run,battle,index)){GUI.enabled=true;EndPage();WinBattle();return;}GUI.enabled=true;GUILayout.Space(9);}GUILayout.EndHorizontal();GUILayout.Space(14);GUILayout.BeginHorizontal();GUILayout.FlexibleSpace();GUI.backgroundColor=new Color(.55f,.17f,.13f);if(GUILayout.Button("ターン終了",button,GUILayout.Width(210),GUILayout.Height(58))){GUI.backgroundColor=Color.white;if(BattleSystem.EndTurn(run,battle,dungeon.damage)){EndPage();FinishRun(false);return;}}GUI.backgroundColor=Color.white;GUILayout.EndHorizontal();EndPage();}
