 bool HomeTile(Rect rect,string icon,string label,string subtitle,bool primary,string notice){bool hover=rect.Contains(UnityEngine.Event.current.mousePosition);Color baseColor=primary?new Color(.31f,.22f,.085f,.96f):new Color(.055f,.071f,.057f,.94f),hoverColor=primary?new Color(.49f,.36f,.13f,.98f):new Color(.13f,.18f,.13f,.98f);GUI.color=hover?hoverColor:baseColor;GUI.DrawTexture(rect,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(rect,hover||primary?gold:new Color(.36f,.29f,.17f),hover?3:primary?2:1);var iconStyle=new GUIStyle(title){alignment=TextAnchor.MiddleCenter,fontSize=primary?34:28};GUI.Label(new Rect(rect.x+12,rect.y+12,primary?62:52,rect.height-24),icon,iconStyle);var tileTitle=new GUIStyle(header){fontSize=primary?22:17,alignment=TextAnchor.MiddleLeft};GUI.Label(new Rect(rect.x+(primary?78:68),rect.y+18,rect.width-(primary?94:82),30),label,tileTitle);GUI.Label(new Rect(rect.x+(primary?79:69),rect.y+50,rect.width-(primary?95:83),34),subtitle,new GUIStyle(screenSubtitle){wordWrap=true});if(!string.IsNullOrEmpty(notice)){Rect mark=new(rect.xMax-57,rect.y+8,47,23);GUI.Label(mark,notice.Length>3?notice:"NEW",badge);}return GUI.Button(rect,GUIContent.none,hotspot);}
