 void MapScreen(){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);BeginPage("ダンジョン探索",dungeon.name);GUILayout.BeginHorizontal();if(GUILayout.Button("▦ 荷造り",button,GUILayout.Width(130),GUILayout.Height(50)))screen=ScreenId.Pack;GUI.enabled=map.current==12;if(GUILayout.Button("← 入口から帰還",button,GUILayout.Width(175),GUILayout.Height(50))){GUI.enabled=true;EndPage();FinishRun(true);return;}GUI.enabled=true;GUILayout.FlexibleSpace();DrawAxisGauge("警戒",run.axes.alert,new Color(.66f,.18f,.16f));GUILayout.Space(8);DrawAxisGauge("崩壊",run.axes.collapse,new Color(.68f,.43f,.12f));GUILayout.Space(8);DrawAxisGauge("汚染",run.axes.corruption,new Color(.44f,.20f,.58f));GUILayout.EndHorizontal();GUILayout.Space(12);Rect area=GUILayoutUtility.GetRect(760,610,GUILayout.ExpandWidth(true));DrawDungeonArt(area,run.dungeon);GUI.color=new Color(.018f,.026f,.020f,.42f);GUI.DrawTexture(area,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(area,new Color(.66f,.48f,.20f),3);float w=area.width/6,h=area.height/6;foreach(var a in map.nodes)foreach(var b in map.nodes.Where(x=>x.id>a.id&&DungeonSystem.Adjacent(a.id,x.id)))DrawMapConnection(area,a,b,w,h,a.visited&&b.visited);foreach(var n in map.nodes){Vector2 center=new(area.x+(n.x+.5f)*w,area.y+(n.y+.5f)*h);Rect r=new(center.x-42,center.y-36,84,72);bool available=n.revealed&&(n.id==map.current||DungeonSystem.Adjacent(map.current,n.id));GUI.enabled=available;GUI.backgroundColor=n.id==map.current?new Color(.82f,.58f,.18f):n.visited?new Color(.20f,.36f,.22f):new Color(.12f,.16f,.13f);string icon=n.type=="battle"?"⚔":n.type=="boss"?"♛":n.type=="shop"?"◆":n.type=="rest"?"♥":n.type=="treasure"?"★":n.type=="event"?"?":n.type=="entrance"?"↑":"·";if(GUI.Button(r,n.revealed?$"{icon}\n{NodeName(n.type)}":"?",n.id==map.current?navSelected:navButton)){if(n.id!=map.current&&DungeonSystem.Move(map,n.id,run))EnterNode(n);}GUI.backgroundColor=Color.white;GUI.enabled=true;if(n.id==map.current)DrawOutline(new Rect(r.x-4,r.y-4,r.width+8,r.height+8),gold,2);}GUI.Label(new Rect(area.x+18,area.yMax-38,area.width-36,28),"明るい区画のみ移動可能  ・  線は探索可能な経路",hubLabel);EndPage();}
 void MapScrollScreen(){
  var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);var zone=DungeonSystem.CurrentZone(map);if(selectedMapNodeId<0||!map.nodes.Any(n=>n.id==selectedMapNodeId))selectedMapNodeId=map.current;
  Color inkColor=new(.20f,.105f,.045f),muted=new(.38f,.24f,.12f);Rect headerRect=new(Screen.width*.15f,Screen.height*.055f,Screen.width*.70f,74f);
  GUI.Label(new Rect(headerRect.x,headerRect.y,headerRect.width*.54f,36),$"{dungeon.name}　―　第{map.currentZone+1}区域 {zone.name}",new GUIStyle(screenTitle){fontSize=Mathf.RoundToInt(Mathf.Clamp(Screen.width*.018f,23f,34f)),fontStyle=FontStyle.Bold,normal={textColor=inkColor}});
  GUI.Label(new Rect(headerRect.x,headerRect.y+39,headerRect.width*.48f,28),$"踏破 {map.nodes.Count(n=>n.visited)}/{map.nodes.Count}　　戦闘 {DungeonSystem.ClearedBattles(map)}/{zone.requiredBattles}",new GUIStyle(body){fontSize=16,fontStyle=FontStyle.Bold,normal={textColor=muted}});
  float gaugeW=headerRect.width*.135f,gaugeGap=10f,gaugeX=headerRect.xMax-gaugeW*3-gaugeGap*2;DrawAxisGaugeAbsolute(new Rect(gaugeX,headerRect.y+8,gaugeW,50),"警戒",run.axes.alert,new Color(.66f,.18f,.16f));DrawAxisGaugeAbsolute(new Rect(gaugeX+gaugeW+gaugeGap,headerRect.y+8,gaugeW,50),"崩壊",run.axes.collapse,new Color(.68f,.43f,.12f));DrawAxisGaugeAbsolute(new Rect(gaugeX+(gaugeW+gaugeGap)*2,headerRect.y+8,gaugeW,50),"侵蝕",run.axes.corruption,new Color(.44f,.20f,.58f));
