 void StatusScreenBook(){Back();BeginPage("役職記録","左頁から習得済みの役職を選び、右頁で成長内容を確認します。");var learned=meta.jobLevels.Where(x=>x.value>0&&GameCatalog.Roles.ContainsKey(x.id)).ToList();if(learned.Count==0){EndPage();return;}if(string.IsNullOrEmpty(selectedRoleId)||!learned.Any(x=>x.id==selectedRoleId))selectedRoleId=meta.currentRole;var selectedLevel=learned.FirstOrDefault(x=>x.id==selectedRoleId)??learned[0];var selectedRole=GameCatalog.Roles[selectedLevel.id];GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label($"習得役職　{learned.Count}種",header);foreach(var level in learned){var role=GameCatalog.Roles[level.id];Rect row=GUILayoutUtility.GetRect(1,92,GUILayout.ExpandWidth(true),GUILayout.Height(92));bool chosen=level.id==selectedRoleId;DrawBookEntrySurface(row,chosen);Rect icon=new(row.x+8,row.y+7,70,78);DrawRoleArt(icon,role.id);GUI.Label(new Rect(row.x+92,row.y+12,row.width-112,28),$"{role.name}　Lv.{level.value}/{role.maxLevel}",new GUIStyle(header){fontSize=17});GUI.Label(new Rect(row.x+93,row.y+43,row.width-114,20),role.kind,body);Rect progress=new(row.x+93,row.y+69,row.width-118,8);GUI.color=new Color(.10f,.085f,.06f);GUI.DrawTexture(progress,Texture2D.whiteTexture);GUI.color=new Color(.75f,.51f,.18f);GUI.DrawTexture(new Rect(progress.x,progress.y,progress.width*Mathf.Clamp01(level.value/(float)role.maxLevel),progress.height),Texture2D.whiteTexture);GUI.color=Color.white;if(GUI.Button(row,GUIContent.none,hotspot))selectedRoleId=level.id;GUILayout.Space(6);}GUILayout.EndVertical();GUILayout.Space(BookPageGutter());GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label("選択中の役職",header);float portraitHeight=BookDetailArtHeight(252f);Rect portraitSlot=GUILayoutUtility.GetRect(1,portraitHeight,GUILayout.ExpandWidth(true),GUILayout.Height(portraitHeight));Rect portrait=FitAspect(portraitSlot,1f);DrawRoleArt(portrait,selectedRole.id);DrawOutline(portrait,selectedRole.id==meta.currentRole?gold:new Color(.49f,.36f,.18f),3);GUILayout.Label($"{selectedRole.name}　Lv.{selectedLevel.value}/{selectedRole.maxLevel}",new GUIStyle(header){fontSize=24});GUILayout.Label(selectedRole.kind+"\n\n"+selectedRole.description,body);GUILayout.Space(12);GUILayout.Label("成長効果",header);DrawRoleMilestone(1,selectedLevel.value,"基礎効果",selectedRole.description);DrawRoleMilestone(7,selectedLevel.value,"専用効果",RoleMilestoneText(selectedRole.id,false));DrawRoleMilestone(selectedRole.maxLevel,selectedLevel.value,"最大レベル効果",RoleMilestoneText(selectedRole.id,true));GUILayout.Space(10);if(selectedRole.id==meta.currentRole)GUILayout.Label("● 現在の役職",hubLabel,GUILayout.Height(44));else GUILayout.Label("転職は専用イベントまたは施設から行います",body);GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
