 void CompendiumScreenBook(){Back();BeginPage("図鑑","左頁の記録を選ぶと、右頁に詳しい情報が開きます。");float tabWidth=Mathf.Max(58f,(BookPageColumnWidth()-16f)/3f);GUILayout.BeginHorizontal(GUILayout.Width(BookPageColumnWidth()));string[] tabs={"装備","役職","敵"};for(int i=0;i<tabs.Length;i++){int tab=i;if(GUILayout.Button((compendiumTab==i?"● ":"")+tabs[i],compendiumTab==i?navSelected:navButton,GUILayout.Width(tabWidth),GUILayout.Height(44))){compendiumTab=tab;selectedCompendiumId="";}}GUILayout.EndHorizontal();GUILayout.Space(10);GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(BookPageColumnWidth()));GUILayout.Label(tabs[compendiumTab]+"一覧",header);if(compendiumTab==0){int column=0;float tileSize=Mathf.Clamp((BookPageColumnWidth()-42f)/4f,76f,96f);int columns=Mathf.Max(2,Mathf.FloorToInt((BookPageColumnWidth()-28f)/(tileSize+8f)));GUILayout.BeginHorizontal();foreach(var item in GameCatalog.Items.Values){Rect tile=GUILayoutUtility.GetRect(tileSize,tileSize,GUILayout.Width(tileSize),GUILayout.Height(tileSize));GUI.color=selectedCompendiumId==item.id?new Color(1f,.82f,.34f):Color.white;DrawItemArt(tile,item.id);GUI.color=Color.white;DrawOutline(tile,selectedCompendiumId==item.id?gold:TypeColor(item.type),selectedCompendiumId==item.id?3:1);if(GUI.Button(tile,GUIContent.none,hotspot))selectedCompendiumId=item.id;column++;if(column%columns==0){GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.BeginHorizontal();}else GUILayout.Space(8);}GUILayout.EndHorizontal();if(string.IsNullOrEmpty(selectedCompendiumId))selectedCompendiumId=GameCatalog.Items.Keys.First();}else if(compendiumTab==1){foreach(var role in GameCatalog.Roles.Values){bool known=meta.jobLevels.Any(x=>x.id==role.id&&x.value>0);if(GUILayout.Button((selectedCompendiumId==role.id?"● ":"")+(known?role.name:"？？？")+"　"+role.kind,button,GUILayout.Height(48)))selectedCompendiumId=role.id;}if(string.IsNullOrEmpty(selectedCompendiumId))selectedCompendiumId=GameCatalog.Roles.Keys.First();}else{foreach(var enemy