 bool DrawLargeBattleHand(Rect area,out bool won){won=false;int count=run.hand.Count;if(count==0){GUI.Label(area,"手札がありません",new GUIStyle(body){fontSize=18,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.90f,.82f,.62f)}});return false;}float gap=10f,maxWidth=215f,minWidth=150f,cardWidth=Mathf.Clamp((area.width-gap*(count-1))/count,minWidth,maxWidth),cardHeight=Mathf.Min(area.height-8,cardWidth*1.36f),total=cardWidth*count+gap*(count-1),x=area.center.x-total*.5f;for(int i=0;i<count;i++){int index=i;var c=run.hand[index];bool affordable=c.cost<=run.energy;Rect baseRect=new(x+i*(cardWidth+gap),area.y+area.height-cardHeight,cardWidth,cardHeight);bool hover=baseRect.Contains(UnityEngine.Event.current.mousePosition);Rect drawRect=hover?new Rect(baseRect.x-8,baseRect.y-18,baseRect.width+16,baseRect.height+18):baseRect;DrawCombatCardV2(drawRect,c,affordable);GUI.enabled=affordable;if(GUI.Button(baseRect,GUIContent.none,hotspot)){GUI.enabled=true;won=BattleSystem.Play(run,battle,index);return true;}GUI.enabled=true;}return false;}
