  GUI.Label(new Rect(rail.center.x-220,rail.y+4,440,rail.height-8),$"EN {run.energy}/3　　山札 {run.draw.Count}　　捨て札 {run.discard.Count}",new GUIStyle(body){fontSize=17,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.94f,.85f,.65f)}});
  Rect endRect=new(rail.xMax-228,rail.y+7,214,rail.height-14);if(GUI.Button(endRect,"ターンを終了",new GUIStyle(button){fontSize=18,fontStyle=FontStyle.Bold})){if(BattleSystem.EndTurn(run,battle,dungeon.damage))FinishRun(false);}
