 bool DrawBattleHandRange(int start,int count,float columnWidth,out bool won){won=false;if(count<=0){GUILayout.Label("この頁にカードはありません。",new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=14},GUILayout.Height(178));return false;}float cardGap=8f,cardWidth=Mathf.Clamp((columnWidth-cardGap*(count-1))/Mathf.Max(1,count),106f,168f),cardHeight=Mathf.Clamp(cardWidth*1.36f,170f,214f);GUILayout.BeginHorizontal(GUILayout.Width(columnWidth));GUILayout.FlexibleSpace();for(int i=0;i<count;i++){int index=start+i;if(index<0||index>=run.hand.Count)break;var combatCard=run.hand[index];bool affordable=combatCard.cost<=run.energy;Rect cardRect=GUILayoutUtility.GetRect(cardWidth,cardHeight,GUILayout.Width(cardWidth),GUILayout.Height(cardHeight));DrawCombatCardV2(cardRect,combatCard,affordable);GUI.enabled=affordable;bool clicked=GUI.Button(cardRect,GUIContent.none,hotspot);GUI.enabled=true;if(clicked){won=BattleSystem.Play(run,battle,index);GUILayout.FlexibleSpace();GUILayout.EndHorizontal();return true;}if(i<count-1)GUILayout.Space(cardGap);}GUILayout.FlexibleSpace();GUILayout.EndHorizontal();return false;}
 void DrawCombatCardV2(Rect slot,CardInstance combatCard,bool affordable){int frameIndex=combatCard.type==CardType.Attack?0:combatCard.type==CardType.Skill?1:2;Texture2D frame=combatCardFrames!=null&&frameIndex<combatCardFrames.Length?combatCardFrames[frameIndex]:null;float frameAspect=frame!=null?frame.width/(float)frame.height:.67f;Rect rect=FitAspect(slot,frameAspect);var sourceItem=run.inventory.FirstOrDefault(x=>x.uid==combatCard.sourceItemUid);if(frame==null)GUI.Box(rect,GUIContent.none,bookEntrySelectedStyle);Rect illustration=new(rect.x+rect.width*.15f,rect.y+rect.height*.10f,rect.width*.70f,rect.height*.505f);GUI.Box(illustration,GUIContent.none,new GUIStyle(){normal={background=bookChipTex},border=new RectOffset(10,10,10,10)});GUI.color=affordable?Color.white:new Color(.43f,.43f,.40f,1);if(sourceItem!=null)DrawItemArt(FitAspect(illustration,1f),sourceItem.templateId);else DrawRoleArt(illustration,run.role);if(frame!=null)GUI.DrawTexture(rect,frame,ScaleMode.StretchToFill,true);GUI.color=Color.white;int titleSize=Mathf.RoundToInt(Mathf.Lerp(12,15,Mathf.InverseLerp(106,168,rect.width))),bodySize=Mathf.RoundToInt(Mathf.Lerp(11,13,Mathf.InverseLerp(106,168,rect.width))),footSize=Mathf.RoundToInt(Mathf.Lerp(10,12,Mathf.InverseLerp(106,168,rect.width)));Rect costRect=new(rect.x+rect.width*.015f,rect.y+rect.height*.015f,rect.width*.255f,rect.width*.255f);DrawFantasyText(costRect,combatCard.cost.ToString(),Mathf.RoundToInt(Mathf.Clamp(rect.width*.14f,17f,22f)),TextAnchor.MiddleCenter,Color.white);GUI.Label(new Rect(rect.x+rect.width*.14f,rect.y+rect.height*.635f,rect.width*.72f,rect.height*.075f),combatCard.name,new GUIStyle(header){alignment=TextAnchor.MiddleCenter,fontSize=titleSize,wordWrap=true,clipping=TextClipping.Clip,normal={textColor=new Color(.96f,.90f,.72f)}});GUI.Label(new Rect(rect.x+rect.width*.14f,rect.y+rect.height*.71f,rect.width*.72f,rect.height*.14f),combatCard.text,new GUIStyle(body){alignment=TextAnchor.UpperCenter,fontSize=bodySize,wordWrap=true,clipping=TextClipping.Clip,normal={textColor=new Color(.90f,.88f,.79f)}});string sourceName=combatCard.source;if(sourceItem!=null&&GameCatalog.Items.TryGetValue(sourceItem.templateId,out var itemDef))sourceName=itemDef.name;GUI.Label(new Rect(rect.x+rect.width*.105f,rect.y+rect.height*.875f,rect.width*.53f,rect.height*.065f),sourceName,new GUIStyle(header){alignment=TextAnchor.MiddleCenter,fontSize=footSize,clipping=TextClipping.Clip,normal={textColor=new Color(.92f,.73f,.35f)}});string durability=sourceItem!=null?$"耐久 {sourceItem.durability}/6":combatCard.roleCard?"役職":"基本";GUI.Label(new Rect(rect.x+rect.width*.65f,rect.y+rect.height*.875f,rect.width*.25f,rect.height*.065f),durability,new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=footSize,normal={textColor=sourceItem!=null&&sourceItem.durability<=1?new Color(1f,.42f,.32f):new Color(.82f,.79f,.66f)}});if(!affordable){Rect lockRect=new(rect.x+rect.width*.58f,rect.y+rect.height*.04f,rect.width*.30f,22);GUI.Box(lockRect,GUIContent.none,new GUIStyle(){normal={background=battleStatusDebuffTex},border=new RectOffset(9,9,9,9)});GUI.Label(lockRect,"EN不足",new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=11,fontStyle=FontStyle.Bold,normal={textColor=Color.white}});}}
 bool DrawConsumableButton(string id,float size=52f){Rect slot=GUILayoutUtility.GetRect(size,size,GUILayout.Width(size),GUILayout.Height(size));bool hover=slot.Contains(UnityEngine.Event.current.mousePosition);GUI.Box(slot,GUIContent.none,hover?bookEntrySelectedStyle:bookEntryStyle);string visual=id=="heal"?"herb":id=="guard"?"buckler":id=="fire"?"bomb":"flask";Rect art=new(slot.x+6,slot.y+4,slot.width-12,slot.height-17);DrawItemArt(art,visual);GUI.Label(new Rect(slot.x+3,slot.yMax-16,slot.width-6,14),ConsumableSystem.Name(id),new GUIStyle(screenSubtitle){alignment=TextAnchor.MiddleCenter,fontSize=10,fontStyle=FontStyle.Bold});return GUI.Button(slot,GUIContent.none,hotspot);}
